#!/usr/bin/env python3
import subprocess, re, sys, os, tempfile, shutil

SRC = "/app/Syzygy_Zopfli/c_code/zopfli.c"
FUNCTION = "TryGetFromLongestMatchCache"
DEPTH = os.environ.get("DEPTH", "200")

# get mutants
out = subprocess.run(["get-mutants","--function",FUNCTION,"--file",SRC],
                     capture_output=True, text=True).stdout
# parse hunks: each has @@ -N +N @@, a '-' line and a '+' line
blocks = out.split("--- original")
mutants = []
for b in blocks:
    if "+++ mutant" not in b: continue
    m = re.search(r"@@ -(\d+) ", b)
    if not m: continue
    ln = int(m.group(1))
    lines = b.splitlines()
    old=new=None
    for l in lines:
        if l.startswith("-") and not l.startswith("---"):
            old = l[1:]
        elif l.startswith("+") and not l.startswith("+++"):
            new = l[1:]
    if old is not None and new is not None:
        mutants.append((ln, old, new))

src_lines = open(SRC).read().split("\n")

def run_verify(path):
    work = "/tmp/_kill_tgflmc"
    shutil.rmtree(work, ignore_errors=True); os.makedirs(work)
    def sh(cmd):
        return subprocess.run(cmd, shell=True, cwd=work, capture_output=True, text=True)
    shutil.copy(path, work+"/mutated.c")
    r = sh(f"goto-cc -D__NO_CTYPE -o m.goto mutated.c -I /app/Syzygy_Zopfli/c_code --function {FUNCTION}")
    if r.returncode != 0:
        return "CCFAIL"
    sh("goto-instrument --add-library m.goto m.goto")
    r = sh(f"goto-instrument --replace-call-with-contract ZopfliMaxCachedSublen --replace-call-with-contract ZopfliCacheToSublen --enforce-contract {FUNCTION} m.goto mc.goto")
    if r.returncode != 0:
        return "INSTFAIL"
    r = sh(f"cbmc mc.goto --function {FUNCTION} --depth {DEPTH}")
    o = r.stdout + r.stderr
    if "VERIFICATION SUCCESSFUL" in o: return "SUCCESS"
    if "VERIFICATION FAILED" in o: return "FAILED"
    return "UNKNOWN:"+o[-200:]

killed=0; total=0; survivors=[]
for (ln, old, new) in mutants:
    total+=1
    idx = ln-1
    if src_lines[idx].strip() != old.strip():
        # try to find
        found=False
        for j in range(max(0,idx-2), min(len(src_lines), idx+3)):
            if src_lines[j].strip()==old.strip():
                idx=j; found=True; break
        if not found:
            print(f"APPLYFAIL line {ln}: {old!r}"); continue
    mut = src_lines[:]
    mut[idx] = mut[idx].replace(old.strip(), new.strip()) if old.strip() in mut[idx] else new
    tf = "/tmp/mutated_tgflmc.c"
    open(tf,"w").write("\n".join(mut))
    res = run_verify(tf)
    if res=="SUCCESS":
        survivors.append((ln,new.strip())); print(f"SURVIVED  L{ln}: {new.strip()}")
    else:
        killed+=1; print(f"KILLED    L{ln}: {new.strip()}  [{res}]")

print(f"\n=== Killed {killed}/{total} (depth {DEPTH}) ===")
if survivors:
    print("Survivors:")
    for s in survivors: print("  ",s)

